"""Always-ready observer for axis testing — no camera or sensor data needed."""

from __future__ import annotations

from franka_policy_runtime.observers.base import BackendObservation, BaseObserver


class AxisTestObserver(BaseObserver):
    """Minimal observer that is always ready with an empty payload."""

    def observe(self) -> BackendObservation:
        return BackendObservation(ready=True, payload={})
